      "path": "src/server.js",
      "content": "const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

function createServer({ dataPath }) {
  const dataFile = path.resolve(dataPath);
  const ensureDataFile = () => {
    if (!fs.existsSync(dataFile)) {
      const initial = { todos: [] };
      fs.writeFileSync(dataFile, JSON.stringify(initial, null, 2));
    }
  };
  ensureDataFile();

  const readData = () => {
    const raw = fs.readFileSync(dataFile, 'utf8');
    return JSON.parse(raw);
  };

  const writeData = (data) => {
    const dir = path.dirname(dataFile);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }
    fs.writeFileSync(dataFile, JSON.stringify(data, null, 2));
  };

  const server = {
    listen: (port, host, cb) => {
      const http = require('http');
      const serverInstance = http.createServer((req, res) => {
        const url = new URL(req.url, `http://${req.headers.host}`);
        const method = req.method.toUpperCase();
        const pathName = url.pathname;

        if (pathName === '/health' && method === 'GET') {
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: true }));
          return;
        }

        if (pathName === '/openapi.json' && method === 'GET') {
          const spec = JSON.parse(fs.readFileSync(path.resolve(__dirname, 'openapi.json'), 'utf8'));
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify(spec));
          return;
        }

        if (pathName.startsWith('/todos')) {
          const idMatch = pathName.match(/^\/todos\/([^/]+)$/);
          const todoId = idMatch ? idMatch[1] : null;

          if (method === 'GET' && !todoId) {
            const todos = readData().todos;
            res.writeHead(200, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify({ ok: true, todos }));
            return;
          }

          if (method === 'POST' && !todoId) {
            let body = '';
            req.on('data', chunk => (body += chunk));
            req.on('end', () => {
              try {
                const { title } = JSON.parse(body);
                if (!title || typeof title !== 'string') {
                  res.writeHead(400, { 'Content-Type': 'application/json' });
                  res.end(JSON.stringify({ ok: false, error: 'Invalid request body' }));
                  return;
                }
                const data = readData();
                data.todos.push({ id: crypto.randomUUID(), title, done: false, createdAt: new Date().toISOString() });
                writeData(data);
                res.writeHead(201, { 'Content-Type': 'application/json' });
                res.end(JSON.stringify({ ok: true, todo: { id: data.todos[data.todos.length - 1].id, title, done: false, createdAt: new Date().toISOString() } }));
              } catch (e) {
                res.writeHead(400, { 'Content-Type': 'application/json' });
                res.end(JSON.stringify({ ok: false, error: 'Invalid JSON' }));
              }
            });
            return;
          }

          if (method === 'PATCH' && todoId) {
            let body = '';
            req.on('data', chunk => (body += chunk));
            req.on('end', () => {
              try {
                const { done } = JSON.parse(body);
                if (!done || typeof done !== 'boolean') {
                  res.writeHead(400, { 'Content-Type': 'application/json' });
                  res.end(JSON.stringify({ ok: false, error: 'Invalid request body' }));
                  return;
                }
                const data = readData();
                const todo = data.todos.find(t => t.id === todoId);
                if (!todo) {
                  res.writeHead(404, { 'Content-Type': 'application/json' });
                  res.end(JSON.stringify({ ok: false, error: 'Todo not found' }));
                  return;
                }
                if (todo.done !== done) {
                  todo.done = done;
                  if (done) {
                    todo.doneAt = new Date().toISOString();
                  } else {
                    todo.doneAt = null;
                  }
                  writeData(data);
                }
                res.writeHead(200, { 'Content-Type': 'application/json' });
                res.end(JSON.stringify({ ok: true, todo }));
              } catch (e) {
                res.writeHead(400, { 'Content-Type': 'application/json' });
                res.end(JSON.stringify({ ok: false, error: 'Invalid JSON' }));
              }
            });
            return;
          }

          if (method === 'DELETE' && todoId) {
            const data = readData();
            const initialLength = data.todos.length;
            data.todos = data.todos.filter(t => t.id !== todoId);
            if (data.todos.length === initialLength) {
              res.writeHead(404, { 'Content-Type': 'application/json' });
              res.end(JSON.stringify({ ok: false, error: 'Todo not found' }));
              return;
            }
            writeData(data);
            res.writeHead(200, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify({ ok: true }));
            return;
          }
        }

        res.writeHead(404, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: false, error: 'Not found' }));
      });
      serverInstance.listen(port, host, () => {
        if (cb) cb();
      });
      return serverInstance;
    }
  };

  return server;
}

module.exports = { createServer };
